<template><div class="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50/30 p-6"><div class="mb-8"><div class="flex items-center justify-between"><div><h1 class="text-3xl font-bold bg-gradient-to-r from-slate-800 to-blue-600 bg-clip-text text-transparent mb-2">🏆 Point Transactions</h1><p class="text-slate-600 font-light">Track reward points</p></div><button @click="refreshData" class="p-2 hover:bg-white/50 rounded-xl transition-all duration-300"><ArrowPathIcon class="w-6 h-6 text-slate-600" /></button></div></div><div v-if="error" class="bg-rose-50 border border-rose-200 rounded-2xl p-6 mb-6"><div class="flex items-center justify-between"><div class="flex items-center space-x-3"><ExclamationTriangleIcon class="w-6 h-6 text-rose-600" /><div><h3 class="text-rose-800 font-semibold">Failed to load transaction data</h3><p class="text-rose-600 text-sm">{{ error }}</p></div></div><button @click="fetchTransactions" class="px-4 py-2 bg-rose-600 text-white rounded-lg hover:bg-rose-700">Retry</button></div></div><div v-if="loading && !error" class="flex items-center justify-center py-20"><div class="text-center"><div class="relative"><div class="w-16 h-16 border-4 border-blue-200 rounded-full"></div><div class="w-16 h-16 border-4 border-transparent border-t-blue-500 rounded-full animate-spin absolute top-0 left-0"></div></div><p class="mt-4 text-slate-500 font-light">Loading transactions...</p></div></div><div v-else-if="!loading" class="space-y-8"><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"><ModernMetricCard title="Total Transactions" :value="stats.total_transactions" icon="🏆" color="blue" :formatted="true" /><ModernMetricCard title="Points Earned" :value="stats.total_earned" icon="⬆️" color="emerald" :formatted="true" /><ModernMetricCard title="Points Redeemed" :value="stats.total_redeemed" icon="⬇️" color="rose" :formatted="true" /><ModernMetricCard title="Net Points" :value="stats.net_points" icon="💎" color="purple" :formatted="true" /></div><SearchBar v-model="searchTerm" placeholder="Search transactions..." :filters="filters" @filter-change="handleFilterChange" @clear="clearFilters" @add="openCreateModal" /><DataTable title="Point Transaction Records" :data="filteredTransactions" :columns="columns" :actions="['delete']" @delete="openDeleteModal"><template #cell-points="{ value }"><span :class="value > 0 ? 'text-emerald-600' : 'text-rose-600'" class="font-medium">{{ value > 0 ? '+' : '' }}{{ value }}</span></template></DataTable></div><FormModal :show="showFormModal" title="Point Transaction" :fields="formFields" :initial-data="selectedTransaction" :loading="saveLoading" @close="closeFormModal" @submit="saveTransaction" /><ConfirmDialog :show="showDeleteModal" title="Delete Transaction" :message="`Delete this point transaction?`" type="danger" :loading="deleteLoading" @confirm="confirmDelete" @cancel="closeDeleteModal" /></div></template><script>import { ref, computed, onMounted } from 'vue';import { useApi } from '../composables/useApi';import ModernMetricCard from '../components/MetricCard.vue';import SearchBar from '../components/SearchBar.vue';import DataTable from '../components/DataTable.vue';import FormModal from '../components/FormModal.vue';import ConfirmDialog from '../components/ConfirmDialog.vue';import { ArrowPathIcon, ExclamationTriangleIcon } from '@heroicons/vue/24/outline';export default {name:'PointTransactions',components:{ModernMetricCard,SearchBar,DataTable,FormModal,ConfirmDialog,ArrowPathIcon,ExclamationTriangleIcon},setup(){const {loading,error,makeRequest}=useApi();const transactions=ref([]);const stats=ref({});const searchTerm=ref('');const activeFilters=ref({});const showFormModal=ref(false);const showDeleteModal=ref(false);const selectedTransaction=ref(null);const transactionToDelete=ref(null);const saveLoading=ref(false);const deleteLoading=ref(false);const columns=[{key:'id',label:'ID',sortable:true},{key:'user_account',label:'User',sortable:true},{key:'transaction_type',label:'Type',sortable:true},{key:'points',label:'Points',sortable:true},{key:'description',label:'Description',sortable:true},{key:'created_at',label:'Date',sortable:true,format:(v)=>v?new Date(v).toLocaleDateString():'N/A'}];const filters=[{key:'transaction_type',label:'Type',options:[{value:'earned_purchase',label:'Purchase'},{value:'earned_referral',label:'Referral'},{value:'redeemed_coupon',label:'Redeemed'}]}];const formFields=[{key:'transaction_type',label:'Type',type:'select',required:true,options:filters[0].options},{key:'points',label:'Points',type:'number',required:true},{key:'description',label:'Description',type:'text',required:true}];const filteredTransactions=computed(()=>{let result=transactions.value;if(searchTerm.value){const term=searchTerm.value.toLowerCase();result=result.filter(t=>t.user_account?.toLowerCase().includes(term)||t.description?.toLowerCase().includes(term))}Object.keys(activeFilters.value).forEach(key=>{const value=activeFilters.value[key];if(value)result=result.filter(t=>t[key]===value)});return result});const fetchTransactions=async()=>{try{const data=await makeRequest('get','point-transactions/');transactions.value=data.results||data}catch(err){console.error('Error:',err)}};const fetchStats=async()=>{try{stats.value=await makeRequest('get','point-transactions/stats/')}catch(err){console.error('Error:',err)}};const refreshData=()=>Promise.all([fetchTransactions(),fetchStats()]);const handleFilterChange=({all})=>{activeFilters.value=all};const clearFilters=()=>{searchTerm.value='';activeFilters.value={}};const openCreateModal=()=>{selectedTransaction.value=null;showFormModal.value=true};const closeFormModal=()=>{showFormModal.value=false;selectedTransaction.value=null};const saveTransaction=async(data)=>{saveLoading.value=true;try{await makeRequest('post','point-transactions/',data);await refreshData();closeFormModal()}catch(err){alert('Error: '+(err.response?.data?.error||err.message))}finally{saveLoading.value=false}};const openDeleteModal=(transaction)=>{transactionToDelete.value=transaction;showDeleteModal.value=true};const closeDeleteModal=()=>{showDeleteModal.value=false;transactionToDelete.value=null};const confirmDelete=async()=>{deleteLoading.value=true;try{await makeRequest('delete',`point-transactions/${transactionToDelete.value.id}/`);await refreshData();closeDeleteModal()}catch(err){alert('Error: '+(err.response?.data?.error||err.message))}finally{deleteLoading.value=false}};onMounted(refreshData);return{loading,error,transactions,stats,searchTerm,showFormModal,showDeleteModal,selectedTransaction,transactionToDelete,saveLoading,deleteLoading,columns,filters,formFields,filteredTransactions,fetchTransactions,refreshData,handleFilterChange,clearFilters,openCreateModal,closeFormModal,saveTransaction,openDeleteModal,closeDeleteModal,confirmDelete}}}</script>
